const data = $json.mensagem_completa;

// Regex para capturar todos os blocos entre colchetes
const matches = data.match(/\[.*?\]/g);

const arraysUnicos = new Set(); // para garantir que não repetimos conteúdo
const resultadoFinal = [];

for (const bloco of matches || []) {
  try {
    // Faz o parse do array
    const array = JSON.parse(bloco);

    // Converte o array em string única, para comparação e retorno
    const frase = array.join(' ');

    // Se ainda não tiver essa frase, adiciona
    if (!arraysUnicos.has(frase)) {
      arraysUnicos.add(frase);
      resultadoFinal.push(frase);
    }
  } catch (e) {
    continue;
  }
}

// Junta tudo em uma string final
const mensagem_lead = resultadoFinal.join(' ');

// Retorno final
return [{ json: { mensagem_lead } }];

