  // Verifica se é imagem (por extensão) ou domínio do Google Drive / Googleusercontent
  return (
    /\.(jpe?g|png|gif|webp|avif|bmp)$/i.test(msg) ||
    /drive\.google\.com|googleusercontent\.com|drive\.usercontent\.google\.com/i.test(msg)
  );
})() }}

