const item = $('puxaDadosTelefone').first();
const valorAiService = item?.json?.ai_service;

// 1. REGRA DE PARADA: Se for "paused" (ou vazio), retorna lista vazia
// O n8n entende isso como "fim da linha" e não executa o próximo nó.
if (!valorAiService || valorAiService === 'paused') {
  return []; 
}

// 2. Se passou da regra acima, retorna o item para o fluxo continuar
return [ item ];
